using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver (resolves any type)
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned metadata for: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? probed))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {probed!.Type.Name}");
}

// Now demonstrate the "not available" path using a resolver that only knows about Person
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
        .WithAddedModifier(ti =>
        {
            // Allow only Person metadata through
            if (ti.Type != typeof(Person))
                ti.CreateObject = null; // still resolves, so use a custom resolver below
        })
};

// Use a custom resolver that explicitly returns null for Order
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine(
        new OnlyPersonResolver())
};

if (restrictedOptions.TryGetTypeInfo<Order>(out JsonTypeInfo<Order>? orderInfo))
{
    Console.WriteLine($"Order info: {orderInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Order> returned false — metadata not available (no exception thrown)");
}

// --- Types -----------------------------------------------------------
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

// A resolver that only provides metadata for Person
file class OnlyPersonResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        if (type == typeof(Person))
            return _inner.GetTypeInfo(type, options);
        return null; // unknown type
    }
}

